package exercicios.oop.java.domain;import java.util.Scanner;public class ParOuImpar {    public Boolean parOuImpar(int num) {        Scanner inputNum = new Scanner(System.in);        System.out.println("Um número: ");        int numDigitado = inputNum.nextInt();        num = numDigitado;        if (num % 2 == 0)            return true;        return false;    }    }